mapper.insert:

    SELECT SEQ_RESIDENT_RQST.nextval FROM dual

INSERT INTO resident_rqst (         /*kr.or.ddit.domain.member.resident.mapper.IResidentMoveMapper.inserMoveOut*/
rqst_no
, apt_cmplex_no
, mvin_prd_dt
, mvout_prd_dt
, rcpt_dt
, rqst_ty_cd
, mvout_rsn_cn
, spcl_cn
, user_no
, ho_no
, mng_no
) VALUES (
#{rqstNo}
, #{aptCmplexNo}
, SYSDATE
, TO_DATE(#{mvoutPrdDt}, 'YYYY-MM-DD')
, SYSDATE
, 'MOVE_OUT'
, #{mvoutRsnCn}
, #{spclCn}
, #{userNo}
, #{hoNo}
, #{mngNo}
)


    SELECT SEQ_RESIDENT_RQST.nextval FROM dual

INSERT INTO resident_rqst (                 /*kr.or.ddit.domain.member.resident.mapper.IResidentMoveMapper.insertMoveIn*/
rqst_no
, apt_cmplex_no
, mvin_prd_dt
, rcpt_dt
, rqst_ty_cd
, spcl_cn
, user_no
, ho_no
, mng_no
) VALUES (
#{rqstNo}
, #{aptCmplexNo}
, TO_DATE(#{mvinPrdDt}, 'YYYY-MM-DD')
, SYSDATE
, 'MOVE_IN'
, #{spclCn}
, #{userNo}
, #{hoNo}
, #{mngNo}
)

mapper.update:
UPDATE hshld_head           /*kr.or.ddit.domain.member.resident.mapper.IResidentMoveMapper.updateInoutCd*/
SET inout_cd = #{inoutCd}
  , move_out_dt = SYSDATE
WHERE user_no = #{userNo}
  AND ho_no = #{hoNo}
